Combine with Metadata

coded_with_meta &lt;- data_speeches_ms2020 |&gt;
  select(.id, speaker, country, regime, dictionary_score = score) |&gt;
  left_join(
    coded_speeches |&gt;
      as.data.frame() |&gt;
      select(.id, llm_score = score, explanation),
    by = ".id"
  )

# View by regime type
coded_with_meta |&gt;
  group_by(regime) |&gt;
  summarise(n = n(), mean_llm = mean(llm_score, na.rm = TRUE))

